const crypto = require('crypto');
const body = JSON.stringify($input.first().json.body);
const signature = $input.first().json.headers['x-specialist-signature'];
const expected = 'sha256=' + crypto.createHmac('sha256', $env.SPECIALIST_SECRET).update(body).digest('hex');
if (signature !== expected) throw new Error('HMAC inválido — specialist signature');
return $input.all();

// G4 — Validação pré-merge do PersonaOutput recebido
const result = $input.first().json.body || $input.first().json;
const validTags = ['AUD','GP','ARQ','DBA','DEV','QA','UX','UI','SEG','CONF','LGPD','NEG'];
const errors = [];

if (result.schema_version !== 'PersonaOutput-v2') errors.push('schema_version inválido');
if (!validTags.includes(result.persona_tag)) errors.push(`persona_tag '${result.persona_tag}' não canônica`);
if (typeof result.score !== 'number' || result.score < 0 || result.score > 100) errors.push('score fora de 0-100');
if (!result.ocg_contributions?.individual) errors.push('ocg_contributions.individual ausente');
if (!result.ocg_contributions?.global_delta) errors.push('ocg_contributions.global_delta ausente');

const valid = errors.length === 0;
const ingestion_id = result.ingestion_id;

return [{json: {result, valid, errors, ingestion_id, persona_tag: result.persona_tag}}];

// Simula Redis accumulator via HTTP ao GCA Backend
// Em produção, substituir por nó Redis nativo ou endpoint interno
const input = $input.first().json;
const ingestion_id = input.ingestion_id;

// RPUSH resultado (válido ou failed)
const resultToStore = input.valid ? input.result : {persona_tag: input.persona_tag, status: 'failed', errors: input.errors};

// Incrementar received_count e verificar se todos chegaram
// Nesta implementação, usamos o GCA Backend como intermediário Redis
const response = await $helpers.httpRequest({
  method: 'POST',
  url: `${$env.GCA_CALLBACK_BASE_URL}/api/internal/ingestion/${ingestion_id}/accumulate`,
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({
    persona_result: resultToStore,
    persona_tag: input.persona_tag,
    valid: input.valid
  }),
  timeout: 10000
});

const allReceived = response.all_received || false;
const receivedCount = response.received_count || 0;
const expectedCount = response.expected_count || 0;
const allResults = response.all_results || [];

return [{json: {ingestion_id, allReceived, receivedCount, expectedCount, allResults, project_id: response.project_id}}];

// Merge de todos os resultados dos especialistas
const input = $input.first().json;
const results = input.allResults || [];

// Pesos por persona (spec v2 §6.4)
const weights = {CONF: 1.5, SEG: 1.3, LGPD: 1.3, AUD: 1.0, ARQ: 1.0, DBA: 1.0, DEV: 0.9, QA: 1.1, GP: 1.0, NEG: 1.0, UX: 0.8, UI: 0.7};

let weightedSum = 0;
let totalWeight = 0;
let blocked = false;
let blockingReason = null;
const personasExecuted = [];
const personasFailed = [];
const mergedIndividual = {};
const mergedGlobalDelta = {};
const allFindings = [];
const allRecommendations = [];
const conflicts = [];

for (const r of results) {
  if (r.status === 'failed') {
    personasFailed.push(r.persona_tag);
    continue;
  }
  personasExecuted.push(r.persona_tag);
  const w = weights[r.persona_tag] || 1.0;
  weightedSum += r.score * w;
  totalWeight += w;

  // Check blocking
  if (r.blocking) {
    blocked = true;
    blockingReason = `${r.persona_tag}: ${r.blocking_reason || 'score < 60'}`;
  }

  // Merge OCG
  mergedIndividual[r.persona_tag] = r.ocg_contributions?.individual || {};
  const delta = r.ocg_contributions?.global_delta || {};
  for (const [k, v] of Object.entries(delta)) {
    if (!mergedGlobalDelta[k]) mergedGlobalDelta[k] = v;
    else if (Array.isArray(v)) mergedGlobalDelta[k] = [...(mergedGlobalDelta[k] || []), ...v];
  }

  // Collect findings/recommendations
  allFindings.push(...(r.findings || []).map(f => ({...f, source_persona: r.persona_tag})));
  allRecommendations.push(...(r.recommendations || []).map(rec => ({...rec, source_persona: r.persona_tag})));
}

const overallScore = totalWeight > 0 ? Math.round(weightedSum / totalWeight) : 0;

// G5 — validação pós-merge
const g5Errors = [];
if (Object.keys(mergedIndividual).length === 0) g5Errors.push('ocg_individual vazio');
if (overallScore === 0 && personasExecuted.length > 0) g5Errors.push('overall_score zerado com personas executadas');

const finalResult = {
  ingestion_id: input.ingestion_id,
  project_id: input.project_id,
  status: g5Errors.length > 0 ? 'partial' : (personasFailed.length > 0 ? 'partial' : 'completed'),
  overall_score: overallScore,
  blocked,
  blocking_reason: blockingReason,
  personas_executed: personasExecuted,
  personas_failed: personasFailed,
  ocg_individual: mergedIndividual,
  ocg_global_delta: mergedGlobalDelta,
  conflicts_resolved: conflicts,
  consolidated_findings: allFindings,
  consolidated_recommendations: allRecommendations,
  execution_summary: {
    total_duration_ms: 0,
    total_tokens: {input: 0, output: 0},
    estimated_cost_usd: 0.0,
    personas_count: personasExecuted.length,
    personas_failed_count: personasFailed.length
  }
};

return [{json: finalResult}];
